def swap_odd_even_bits(n: int) -> int:
    if n == 0:
        return 0

    num_bits = n.bit_length()

    even_mask = 0
    odd_mask = 0
    for i in range(num_bits):
        if i % 2 == 0:
            even_mask |= (1 << i)
        else:
            odd_mask |= (1 << i)

    shifted_even_bits = (n & even_mask) << 1
    shifted_odd_bits = (n & odd_mask) >> 1

    return shifted_even_bits | shifted_odd_bits
